define <2 x i16> @zext_lshr_vec_undef(<2 x i8> %x) {
  %z = zext <2 x i8> %x to <2 x i16>
  %b = lshr <2 x i16> %z, undef
  %r = and <2 x i16> %b, %z
  ret <2 x i16> %r
}

define <2 x i16> @zext_shl_vec_overshift(<2 x i8> %x) {
  %z = zext <2 x i8> %x to <2 x i16>
  %b = shl <2 x i16> %z, <i16 8, i16 2>
  %r = and <2 x i16> %b, %z
  ret <2 x i16> %r
}

define <2 x i8> @lshr_shl_demand5_nonuniform_vec_left(<2 x i8> %x) {
  %shr = lshr <2 x i8> <i8 45, i8 45>, %x
  %shl = shl <2 x i8> %shr, <i8 1, i8 2>
  %r = and <2 x i8> %shl, <i8 108, i8 108>
  ret <2 x i8> %r
}

define <2 x i8> @lshr_shl_demand5_undef_right(<2 x i8> %x) {
  %shr = lshr <2 x i8> <i8 undef, i8 45>, %x
  %shl = shl <2 x i8> %shr, <i8 2, i8 2>
  %r = and <2 x i8> %shl, <i8 108, i8 108>
  ret <2 x i8> %r
}

define <2 x i6> @shl_lshr_demand5_nonuniform_vec_left(<2 x i8> %x) {
  %shl = shl <2 x i8> <i8 -108, i8 -108>, %x
  %lshr = lshr <2 x i8> %shl, <i8 1, i8 2>
  %r = trunc <2 x i8> %lshr to <2 x i6>
  ret <2 x i6> %r
}

define <2 x i6> @shl_lshr_demand5_undef_right(<2 x i8> %x) {
  %shl = shl <2 x i8> <i8 -108, i8 -108>, %x
  %lshr = lshr <2 x i8> %shl, <i8 undef, i8 2>
  %r = trunc <2 x i8> %lshr to <2 x i6>
  ret <2 x i6> %r
}
